<script setup lang="ts">
import{Head,Link}from'@inertiajs/vue3';import{Bookmark,Eye,Heart,MessageCircle,Play,Search,X}from'@lucide/vue';import{computed,onMounted,ref}from'vue';import AppShell from '../../Layouts/AppShell.vue';
const videos=ref<any[]>([]),loading=ref(true),query=ref(''),active=ref<any>(),busy=ref('');const filtered=computed(()=>videos.value.filter(v=>!query.value||`${v.caption} ${v.creator?.name} ${v.sport?.name}`.toLowerCase().includes(query.value.toLowerCase()))),compact=(n:number)=>new Intl.NumberFormat('en',{notation:'compact',maximumFractionDigits:1}).format(n??0),csrf=()=>document.querySelector<HTMLMetaElement>('meta[name="csrf-token"]')?.content??'';const load=async()=>{const r=await fetch('/api/v1/feed/saved?per_page=50',{credentials:'same-origin',headers:{Accept:'application/json'}});videos.value=(await r.json()).data??[];loading.value=false};const unsave=async(v:any)=>{busy.value=v.id;const r=await fetch(`/api/v1/videos/${v.id}/save`,{method:'POST',credentials:'same-origin',headers:{Accept:'application/json','Content-Type':'application/json','X-CSRF-TOKEN':csrf()},body:'{}'});if(r.ok)videos.value=videos.value.filter(x=>x.id!==v.id);busy.value=''};onMounted(load);
</script>
<template><Head title="Saved Videos"/><AppShell><main class="saved-page"><header class="saved-heading"><div><h1>Saved videos</h1><p>Your private collection of highlights, athletes and sporting moments.</p></div><div><Search/><input v-model="query" placeholder="Search saved videos..."/></div></header><div class="saved-summary"><h2>{{loading?'Loading…':`${filtered.length} saved videos`}}</h2><Link href="/feed">Discover more</Link></div><section v-if="!loading&&filtered.length" class="saved-grid"><article v-for="video in filtered" :key="video.id" class="saved-card"><button class="saved-preview" @click="active=video"><video :src="video.media?.download_url" muted preload="metadata"/><span><Play fill="white"/></span><small><Eye/>{{compact(video.counts?.views)}}</small></button><div class="saved-card-body"><div class="saved-creator"><span>{{video.creator?.name?.slice(0,2).toUpperCase()}}</span><div><Link :href="`/@${video.creator?.slug}`">{{video.creator?.name}}</Link><small>{{video.sport?.name||'SportUniverse athlete'}}</small></div></div><p>{{video.caption||'SportUniverse video'}}</p><footer><span><Heart/>{{compact(video.counts?.likes)}}</span><span><MessageCircle/>{{compact(video.counts?.comments)}}</span><button :disabled="busy===video.id" @click="unsave(video)"><Bookmark fill="currentColor"/>{{busy===video.id?'Removing…':'Saved'}}</button></footer></div></article></section><section v-else-if="!loading" class="saved-empty"><Bookmark/><h2>{{query?'No matching saved videos':'Your saved collection is empty'}}</h2><p>{{query?'Try another search term.':'Save videos from your feed to watch them again later.'}}</p><Link href="/feed">Explore videos</Link></section></main><div v-if="active" class="saved-player" @click.self="active=null"><section><button @click="active=null"><X/></button><video :src="active.media?.download_url" autoplay controls playsinline/><div><strong>{{active.creator?.name}}</strong><p>{{active.caption}}</p></div></section></div></AppShell></template>
